import React, { useState } from 'react';
import axios from 'axios';
import '../assets/styles/Skype.css'; // Presupunem că stilurile pentru Skype se vor afla aici

const Skype = ({ onClose }) => {
  const [errorMessage, setErrorMessage] = useState('');
  const [showConfirm, setShowConfirm] = useState(false); // Stare pentru confirmare închidere

  const handleSkypeAction = (endpoint) => {
    axios.post(`/shortcuts/skype/${endpoint}/`)
      .then(response => {
        console.log(response.data.message || 'Action performed successfully');
        setErrorMessage(''); // Resetăm orice eroare
      })
      .catch(error => {
        console.error('There was an error performing the action!', error);
        setErrorMessage('There was an error performing the action.');
      });
  };

  const confirmCloseSkype = () => {
    setShowConfirm(true); // Afișează confirmarea pentru închidere
  };

  const handleCloseSkype = () => {
    handleSkypeAction('close-skype');
    setShowConfirm(false); // Ascunde dialogul de confirmare după închidere
  };

  return (
    <div className="skype-container">
      <h1 className="title">Skype</h1>

      <div className="button-group">
        <h2>Chats</h2>
        <button onClick={() => handleSkypeAction('open-chats')} className="button">
          <i className="fas fa-comments"></i> Chats
        </button>
        <button onClick={() => handleSkypeAction('open-contacts')} className="button">
          <i className="fas fa-address-book"></i> Contacts
        </button>
        <button onClick={() => handleSkypeAction('next-conversation')} className="button">
          <i className="fas fa-arrow-right"></i> Next Conversation
        </button>
        <button onClick={() => handleSkypeAction('previous-conversation')} className="button">
          <i className="fas fa-arrow-left"></i> Previous Conversation
        </button>
      </div>

      <div className="button-group">
        <h2>Apeluri</h2>
        <button onClick={() => handleSkypeAction('start-video-call')} className="button">
          <i className="fas fa-video"></i> Video Call
        </button>
        <button onClick={() => handleSkypeAction('start-audio-call')} className="button">
          <i className="fas fa-phone"></i> Audio Call
        </button>
        <button onClick={() => handleSkypeAction('toggle-mute')} className="button">
          <i className="fas fa-microphone-slash"></i> Toggle Mute
        </button>
        <button onClick={() => handleSkypeAction('toggle-camera')} className="button">
          <i className="fas fa-camera"></i> Toggle Camera
        </button>
        <button onClick={() => handleSkypeAction('add-people-to-call')} className="button">
          <i className="fas fa-user-plus"></i> Add People
        </button>
      </div>

      <div className="button-container">
        <h2>General</h2>
        <button onClick={() => handleSkypeAction('open-skype')} className="button open-skype-button">
          <i className="fas fa-external-link-alt"></i> Adu în față Skype
        </button>
        <button onClick={confirmCloseSkype} className="button close-skype-button">
          <i className="fas fa-times"></i> Închide Skype
        </button>
      </div>

      {errorMessage && (
        <div className="error-message">
          {errorMessage}
        </div>
      )}

      {showConfirm && (
        <div className="modal">
          <div className="modal-content">
            <p>Ești sigur că vrei să închizi Skype?</p>
            <button onClick={handleCloseSkype} className="confirm-button">Da</button>
            <button onClick={() => setShowConfirm(false)} className="cancel-button">Nu</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Skype;
